{
  "name": "Memphis Focus Tasks",
  "description": "A focused, Memphis-design task manager that displays only the top 2 tasks, featuring dynamic category filtering, multiple ranking systems, and persistence."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum RankingCriteria {
  PRIORITY = 'PRIORITY',
  BOTHERED = 'BOTHERED',
  DIFFICULTY = 'DIFFICULTY',
  CATEGORY = 'CATEGORY',
}

export type PriorityLevel = 'High' | 'Medium' | 'Low';

export interface Task {
  id: string;
  title: string;
  description: string;
  priority: PriorityLevel;
  botheredLevel: number; // 1-10
  difficultyMinutes: number;
  category: string;
  tagColor: string;
  deadline?: string; // ISO string
  createdAt: number;
  completedAt?: number;
}

export interface TagOption {
  color: string;
  label?: string; // Optional label for predefined colors
}

export const PRIORITY_MAP: Record<PriorityLevel, number> = {
  High: 3,
  Medium: 2,
  Low: 1,
};

export const DEFAULT_COLORS = [
  '#ff90e8', // Pink
  '#ffc900', // Yellow
  '#23a6d5', // Blue
  '#90e0ef', // Mint
  '#b185db', // Purple
  '#ff6b6b', // Red
  '#feca57', // Orange
  '#48dbfb', // Cyan
  '#ff9ff3', // Rose
  '#54a0ff', // Light Blue
  '#5f27cd', // Dark Purple
  '#1dd1a1', // Green
];

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'success';
  size?: 'sm' | 'md' | 'lg';
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  className = '', 
  ...props 
}) => {
  const baseStyles = "font-bold border-2 border-black transition-all transform active:translate-x-[2px] active:translate-y-[2px] active:shadow-memphis-active disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-memphis-yellow text-black shadow-memphis hover:-translate-y-0.5 hover:shadow-memphis-hover",
    secondary: "bg-white text-black shadow-memphis hover:-translate-y-0.5 hover:shadow-memphis-hover",
    danger: "bg-red-400 text-white shadow-memphis hover:-translate-y-0.5 hover:shadow-memphis-hover",
    success: "bg-memphis-mint text-black shadow-memphis hover:-translate-y-0.5 hover:shadow-memphis-hover",
  };

  const sizes = {
    sm: "px-3 py-1 text-sm",
    md: "px-4 py-2",
    lg: "px-6 py-3 text-lg",
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${className}`}
      {...props}
    >
      {children}
    </button>
  );
};

import React from 'react';

interface InputProps extends React.InputHTMLAttributes<HTMLInputElement> {
