import React from 'react';
import { RankingCriteria } from '../types';
import { ArrowUpNarrowWide, Zap, Brain, Tags } from 'lucide-react';

interface RankingSelectorProps {
  currentRanking: RankingCriteria;
  onRankingChange: (criteria: RankingCriteria) => void;
}

export const RankingSelector: React.FC<RankingSelectorProps> = ({ 
  currentRanking, 
  onRankingChange 
}) => {
  const options = [
    { id: RankingCriteria.PRIORITY, label: 'Priority', icon: <ArrowUpNarrowWide size={16} /> },
    { id: RankingCriteria.BOTHERED, label: 'Bothered', icon: <Zap size={16} /> },
    { id: RankingCriteria.DIFFICULTY, label: 'Difficulty', icon: <Brain size={16} /> },
    { id: RankingCriteria.CATEGORY, label: 'Category', icon: <Tags size={16} /> },
  ];

  return (
    <div className="bg-white border-2 border-black shadow-memphis p-4 mb-6">
      <div className="flex flex-col sm:flex-row items-center justify-between gap-4">
        <span className="font-bold text-lg flex items-center gap-2">
           Sort Tasks By:
        </span>
        <div className="flex flex-wrap gap-2">
          {options.map((option) => (
            <button
              key={option.id}
              onClick={() => onRankingChange(option.id)}
              className={`
                flex items-center gap-2 px-3 py-2 border-2 border-black font-medium text-sm transition-all
                ${currentRanking === option.id 
                  ? 'bg-memphis-pink shadow-[2px_2px_0px_0px_#1a1a1a] translate-x-[-1px] translate-y-[-1px]' 
                  : 'bg-white hover:bg-gray-50'
                }
              `}
            >
              {option.icon}
              {option.label}
            </button>
          ))}
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { Task } from '../types';
import { Check, Edit2, Clock, Calendar, AlertCircle } from 'lucide-react';
import { format } from 'date-fns';

interface TaskCardProps {
  task: Task;
  onComplete: (id: string) => void;
  onEdit: (task: Task) => void;
  isTopTask?: boolean;
}

export const TaskCard: React.FC<TaskCardProps> = ({ task, onComplete, onEdit, isTopTask }) => {
  // Dynamic background based on priority if it's a top task, otherwise simpler
  const getBgColor = () => {
    if (!isTopTask) return 'bg-white';
    switch (task.priority) {
      case 'High': return 'bg-red-100';
      case 'Medium': return 'bg-memphis-yellow';
      case 'Low': return 'bg-memphis-mint';
      default: return 'bg-white';
    }
  };

  return (
    <div 
      className={`
        relative border-2 border-black p-5 transition-all
        ${isTopTask ? 'shadow-memphis hover:shadow-memphis-hover transform hover:-translate-y-1' : 'shadow-sm opacity-80 hover:opacity-100'}
        ${getBgColor()}
      `}
    >
      {/* Category Tag Badge */}
      <div 
        className="absolute -top-3 -right-3 px-3 py-1 border-2 border-black text-xs font-bold shadow-[2px_2px_0px_0px_#000]"
        style={{ backgroundColor: task.tagColor }}
      >
        {task.category}
      </div>

      <div className="flex justify-between items-start mb-2 mt-1">
        <h3 className="text-xl font-bold leading-tight w-3/4">{task.title}</h3>
        <button 
          onClick={() => onEdit(task)}
          className="p-1.5 hover:bg-black/10 rounded border border-transparent hover:border-black transition-colors"
          title="Edit Task"
        >
          <Edit2 size={16} />
        </button>
      </div>

      {task.description && (
        <p className="text-sm text-gray-700 mb-4 line-clamp-2">{task.description}</p>
      )}

      {/* Metadata Grid */}
      <div className="grid grid-cols-2 gap-2 text-xs font-medium mb-4">
        <div className="flex items-center gap-1.5" title="Deadline">
           <Calendar size={14} className="text-memphis-purple" />
           {task.deadline ? (
             <span className={new Date(task.deadline) < new Date() ? 'text-red-600 font-bold' : ''}>
               {format(new Date(task.deadline), 'MMM d, h:mm a')}
             </span>
           ) : <span className="text-gray-400">No Deadline</span>}
        </div>

        <div className="flex items-center gap-1.5" title="Difficulty">
           <Clock size={14} className="text-memphis-blue" />
           {task.difficultyMinutes} mins
        </div>

        <div className="flex items-center gap-1.5" title="Priority">
           <AlertCircle size={14} className={task.priority === 'High' ? 'text-red-500' : 'text-gray-600'} />
           {task.priority}
        </div>

        <div className="flex items-center gap-1.5" title="Bother Level">
           <span className="text-lg leading-none">😫</span>
           Lvl {task.botheredLevel}
        </div>
      </div>

      {/* Complete Action - Only prominent for top tasks */}
      {isTopTask ? (
        <button 
          onClick={() => onComplete(task.id)}
          className="w-full flex items-center justify-center gap-2 bg-black text-white font-bold py-3 hover:bg-gray-800 transition-colors border-2 border-transparent active:border-white"
        >
          <Check size={20} />
          CROSS OUT
        </button>
      ) : (
        <div className="text-center text-xs text-gray-500 italic border-t border-black/10 pt-2">
          Waiting in backup...
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Task, PriorityLevel, DEFAULT_COLORS } from '../../types';
import { Button } from '../ui/Button';
import { Input, Select } from '../ui/Input';
import { X } from 'lucide-react';

interface TaskModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (task: Omit<Task, 'id' | 'createdAt' | 'completedAt'>) => void;
  initialTask?: Task | null;
}

export const TaskModal: React.FC<TaskModalProps> = ({ isOpen, onClose, onSave, initialTask }) => {
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [priority, setPriority] = useState<PriorityLevel>('Medium');
  const [botheredLevel, setBotheredLevel] = useState(5);
  const [difficultyMinutes, setDifficultyMinutes] = useState(30);
  const [category, setCategory] = useState('');
  const [tagColor, setTagColor] = useState(DEFAULT_COLORS[0]);
  const [deadlineDate, setDeadlineDate] = useState('');
  const [deadlineTime, setDeadlineTime] = useState('');

  // Reset or Load initial data
  useEffect(() => {
    if (isOpen) {
      if (initialTask) {
        setTitle(initialTask.title);
        setDescription(initialTask.description || '');
        setPriority(initialTask.priority);
        setBotheredLevel(initialTask.botheredLevel);
        setDifficultyMinutes(initialTask.difficultyMinutes);
        setCategory(initialTask.category);
        setTagColor(initialTask.tagColor);

        if (initialTask.deadline) {
          const d = new Date(initialTask.deadline);
          // Format for input type="date" and "time"
          setDeadlineDate(d.toISOString().split('T')[0]);
          setDeadlineTime(d.toTimeString().slice(0, 5));
        } else {
            setDeadlineDate('');
            setDeadlineTime('');
        }
      } else {
        // Defaults
        setTitle('');
        setDescription('');
        setPriority('Medium');
        setBotheredLevel(5);
        setDifficultyMinutes(30);
        setCategory('');
        setTagColor(DEFAULT_COLORS[Math.floor(Math.random() * DEFAULT_COLORS.length)]);
        setDeadlineDate('');
        setDeadlineTime('');
      }
    }
  }, [isOpen, initialTask]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!title.trim() || !category.trim()) return;

    let deadlineIso: string | undefined = undefined;
    if (deadlineDate) {
        const time = deadlineTime || '23:59';
        deadlineIso = new Date(`${deadlineDate}T${time}`).toISOString();
    }

    onSave({
      title,
      description,
      priority,
      botheredLevel,
      difficultyMinutes,
      category,
      tagColor,
      deadline: deadlineIso,
    });
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
      <div className="bg-white border-2 border-black shadow-[8px_8px_0px_0px_rgba(255,144,232,1)] w-full max-w-lg max-h-[90vh] overflow-y-auto">
        <div className="p-4 border-b-2 border-black flex justify-between items-center bg-memphis-yellow">
          <h2 className="text-xl font-bold">{initialTask ? 'Edit Task' : 'New Task'}</h2>
          <button onClick={onClose} className="p-1 hover:bg-black/10 rounded"><X size={24} /></button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-5">
          <Input 
            label="What needs to be done?" 
            value={title} 
            onChange={e => setTitle(e.target.value)} 
            placeholder="e.g. Finish the report"
            required
            autoFocus
          />

          <div className="flex flex-col gap-1">
            <label className="font-bold text-sm">Description</label>
            <textarea 
              className="border-2 border-black p-2 shadow-[2px_2px_0px_0px_rgba(0,0,0,1)] focus:outline-none focus:shadow-[4px_4px_0px_0px_rgba(0,0,0,1)] w-full resize-none h-20"
              value={description}
              onChange={e => setDescription(e.target.value)}
              placeholder="Add details..."
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
             <div className="col-span-1">
                <Select label="Priority" value={priority} onChange={e => setPriority(e.target.value as PriorityLevel)}>
                    <option value="High">High</option>
                    <option value="Medium">Medium</option>
                    <option value="Low">Low</option>
                </Select>
             </div>
             <div className="col-span-1">
                <Input 
                    type="number" 
                    label="Est. Minutes" 
                    min="1" 
                    value={difficultyMinutes} 
                    onChange={e => setDifficultyMinutes(Number(e.target.value))} 
                />
             </div>
          </div>

          <div>
             <label className="font-bold text-sm block mb-1">Bothered Level (1-10)</label>
             <div className="flex items-center gap-3">
                <span className="text-xl">😌</span>
                <input 
                    type="range" 
                    min="1" 
                    max="10" 
                    value={botheredLevel} 
                    onChange={e => setBotheredLevel(Number(e.target.value))} 
                    className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer border border-black accent-memphis-purple"
                />
                <span className="text-xl">😫</span>
                <span className="font-bold w-6 text-center">{botheredLevel}</span>
             </div>
          </div>

          {/* Tag & Color System */}
          <div className="border-2 border-black p-4 bg-gray-50 relative">
             <label className="absolute -top-3 left-3 bg-gray-50 px-2 font-bold text-sm">Category & Tag</label>
             <div className="flex gap-4 items-end">
                <div className="flex-1">
                    <Input 
                        label="Category Name" 
                        value={category} 
                        onChange={e => setCategory(e.target.value)} 
                        placeholder="e.g. Work, Health"
                        list="existing-categories"
                        required
                    />
                </div>
                <div className="flex flex-col gap-1">
                    <label className="text-xs font-bold">Color</label>
                    <input 
                        type="color" 
                        value={tagColor} 
                        onChange={e => setTagColor(e.target.value)}
                        className="h-[42px] w-[50px] border-2 border-black p-0 cursor-pointer"
                    />
                </div>
             </div>

             {/* Preset Colors */}
             <div className="flex flex-wrap gap-2 mt-3">
                {DEFAULT_COLORS.map(c => (
                    <button
                        key={c}
                        type="button"
                        onClick={() => setTagColor(c)}
                        className={`w-6 h-6 rounded-full border border-black ${tagColor === c ? 'ring-2 ring-offset-1 ring-black scale-110' : ''}`}
                        style={{ backgroundColor: c }}
                    />
                ))}
             </div>
          </div>

          {/* Deadline System */}
          <div className="grid grid-cols-2 gap-4">
             <Input 
                type="date" 
                label="Deadline Date" 
                value={deadlineDate}
                onChange={e => setDeadlineDate(e.target.value)}
             />
             <Input 
                type="time" 
                label="Time" 
                value={deadlineTime}
                onChange={e => setDeadlineTime(e.target.value)}
                disabled={!deadlineDate}
             />
          </div>

          <div className="pt-4 flex justify-end gap-3">
             <Button type="button" variant="secondary" onClick={onClose}>Cancel</Button>
             <Button type="submit" variant="primary">
                 {initialTask ? 'Update Task' : 'Add Task'}
             </Button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React from 'react';
import { Task } from '../../types';
import { X, CalendarCheck } from 'lucide-react';
import { format } from 'date-fns';

interface HistoryModalProps {
  isOpen: boolean;
  onClose: () => void;
  completedTasks: Task[];
  onClearHistory: () => void;
}

export const HistoryModal: React.FC<HistoryModalProps> = ({ isOpen, onClose, completedTasks, onClearHistory }) => {
  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
      <div className="bg-white border-2 border-black shadow-[8px_8px_0px_0px_#23a6d5] w-full max-w-lg max-h-[80vh] flex flex-col">
        <div className="p-4 border-b-2 border-black flex justify-between items-center bg-memphis-mint">
          <h2 className="text-xl font-bold flex items-center gap-2">
            <CalendarCheck /> Task History
          </h2>
          <button onClick={onClose} className="p-1 hover:bg-black/10 rounded"><X size={24} /></button>
        </div>

        <div className="flex-1 overflow-y-auto p-4">
          {completedTasks.length === 0 ? (
            <div className="text-center py-10 text-gray-500">No completed tasks yet. Get to work!</div>
          ) : (
            <div className="space-y-3">
              {[...completedTasks].sort((a,b) => (b.completedAt || 0) - (a.completedAt || 0)).map(task => (
                <div key={task.id} className="border-b-2 border-gray-100 pb-3 last:border-0">
                  <div className="flex justify-between items-start">
                    <h4 className="font-bold line-through text-gray-500 decoration-2">{task.title}</h4>
                    <span 
                        className="text-[10px] px-2 py-0.5 border border-black font-bold"
                        style={{ backgroundColor: task.tagColor }}
                    >
                        {task.category}
                    </span>
                  </div>
                  <p className="text-xs text-gray-400 mt-1">
                    Completed: {task.completedAt ? format(task.completedAt, 'PPp') : 'Unknown'}
                  </p>
                </div>
              ))}
            </div>
          )}
        </div>

        {completedTasks.length > 0 && (
            <div className="p-4 border-t-2 border-black bg-gray-50">
                <button 
                    onClick={onClearHistory}
                    className="w-full py-2 text-sm text-red-500 font-bold hover:bg-red-50 border border-transparent hover:border-red-200 transition-colors"
                >
                    Clear History
                </button>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { Task, RankingCriteria, PRIORITY_MAP } from './types';
import { Button } from './components/ui/Button';
import { CategoryFilter } from './components/CategoryFilter';
import { RankingSelector } from './components/RankingSelector';
import { TaskCard } from './components/TaskCard';
import { TaskModal } from './components/modals/TaskModal';
import { HistoryModal } from './components/modals/HistoryModal';
import { Plus, History } from 'lucide-react';

export default function App() {
  // State
  const [tasks, setTasks] = useState<Task[]>([]);
  const [completedTasks, setCompletedTasks] = useState<Task[]>([]);
  const [rankingMethod, setRankingMethod] = useState<RankingCriteria>(RankingCriteria.PRIORITY);
  const [activeCategory, setActiveCategory] = useState<string>('All');

  // Modal States
  const [isTaskModalOpen, setIsTaskModalOpen] = useState(false);
  const [editingTask, setEditingTask] = useState<Task | null>(null);
  const [isHistoryModalOpen, setIsHistoryModalOpen] = useState(false);

  // Persistence on Mount
  useEffect(() => {
    const storedTasks = localStorage.getItem('memphis-tasks');
    const storedCompleted = localStorage.getItem('memphis-completed');
    const storedRanking = localStorage.getItem('memphis-ranking');

    if (storedTasks) setTasks(JSON.parse(storedTasks));
    if (storedCompleted) setCompletedTasks(JSON.parse(storedCompleted));
    if (storedRanking) setRankingMethod(storedRanking as RankingCriteria);
  }, []);

  // Persistence on Update
  useEffect(() => {
    localStorage.setItem('memphis-tasks', JSON.stringify(tasks));
  }, [tasks]);

  useEffect(() => {
    localStorage.setItem('memphis-completed', JSON.stringify(completedTasks));
  }, [completedTasks]);

  useEffect(() => {
    localStorage.setItem('memphis-ranking', rankingMethod);
  }, [rankingMethod]);

  // Derived Data
  const categories = useMemo(() => {
    const uniqueCats = new Set(tasks.map(t => t.category).filter(Boolean));
    return Array.from(uniqueCats).sort();
  }, [tasks]);

  const sortedTasks = useMemo(() => {
    let filtered = activeCategory === 'All' 
      ? tasks 
      : tasks.filter(t => t.category === activeCategory);

    return [...filtered].sort((a, b) => {
      switch (rankingMethod) {
        case RankingCriteria.PRIORITY:
          // High (3) > Medium (2) > Low (1)
          if (PRIORITY_MAP[b.priority] !== PRIORITY_MAP[a.priority]) {
            return PRIORITY_MAP[b.priority] - PRIORITY_MAP[a.priority];
          }
          return b.createdAt - a.createdAt; // Tiebreaker: Newest first

        case RankingCriteria.BOTHERED:
          // Higher bothered level comes first
          if (b.botheredLevel !== a.botheredLevel) {
            return b.botheredLevel - a.botheredLevel;
          }
          return PRIORITY_MAP[b.priority] - PRIORITY_MAP[a.priority];

        case RankingCriteria.DIFFICULTY:
          // Sort by difficulty (Minutes) descending (Hardest first)
          // Users often want to tackle biggest tasks first in this mode
          if (b.difficultyMinutes !== a.difficultyMinutes) {
            return b.difficultyMinutes - a.difficultyMinutes;
          }
          return PRIORITY_MAP[b.priority] - PRIORITY_MAP[a.priority];

        case RankingCriteria.CATEGORY:
            // Sort by Category Name AZ, then Priority
            const catCompare = a.category.localeCompare(b.category);
            if (catCompare !== 0) return catCompare;
            return PRIORITY_MAP[b.priority] - PRIORITY_MAP[a.priority];

        default:
          return b.createdAt - a.createdAt;
      }
    });
  }, [tasks, activeCategory, rankingMethod]);

  // Top 2 tasks to focus on
  const topTasks = sortedTasks.slice(0, 2);
  const backupTasks = sortedTasks.slice(2);

  // Handlers
  const handleAddTask = (taskData: Omit<Task, 'id' | 'createdAt' | 'completedAt'>) => {
    const newTask: Task = {
      ...taskData,
      id: uuidv4(),
      createdAt: Date.now(),
    };
    setTasks(prev => [...prev, newTask]);

    // Automatically switch to the new category if we are filtering, 
    // unless the user is on 'All', or maybe keep them where they are.
    // If user adds a task in "Work" but is viewing "Health", it disappears.
    // Let's reset to All to show feedback, or switch to that category.
    // Sticking to "All" is safer for visibility.
    if (activeCategory !== 'All' && taskData.category !== activeCategory) {
        setActiveCategory('All');
    }
  };

  const handleEditTask = (taskData: Omit<Task, 'id' | 'createdAt' | 'completedAt'>) => {
    if (!editingTask) return;

    setTasks(prev => prev.map(t => 
        t.id === editingTask.id 
            ? { ...t, ...taskData } 
            : t
    ));
    setEditingTask(null);
  };

  const handleCompleteTask = (id: string) => {
    const taskToComplete = tasks.find(t => t.id === id);
    if (taskToComplete) {
      const completed: Task = { ...taskToComplete, completedAt: Date.now() };
      setCompletedTasks(prev => [...prev, completed]);
      setTasks(prev => prev.filter(t => t.id !== id));
    }
  };

  const handleOpenEdit = (task: Task) => {
    setEditingTask(task);
    setIsTaskModalOpen(true);
  };

  const handleClearHistory = () => {
      if(window.confirm("Are you sure you want to clear all history?")) {
          setCompletedTasks([]);
      }
  };

  return (
    <div className="min-h-screen pb-20 px-4 md:px-8 max-w-5xl mx-auto pt-8">

      {/* Header */}
      <header className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
        <div>
           <h1 className="text-4xl md:text-5xl font-black text-black tracking-tight mb-2 relative inline-block">
             FOCUS TASKS
             <div className="absolute -bottom-2 left-0 w-full h-3 bg-memphis-yellow -z-10 opacity-70 transform -rotate-1"></div>
           </h1>
           <p className="text-gray-600 font-medium">Get it done. Two at a time.</p>
        </div>

        <div className="flex gap-3">
            <Button onClick={() => setIsHistoryModalOpen(true)} variant="secondary" className="flex items-center gap-2">
                <History size={18} /> History ({completedTasks.length})
            </Button>
            <Button onClick={() => { setEditingTask(null); setIsTaskModalOpen(true); }} className="flex items-center gap-2">
                <Plus size={20} strokeWidth={3} /> Add Task
            </Button>
        </div>
      </header>

      {/* Controls */}
      {categories.length > 0 && (
          <CategoryFilter 
            categories={categories} 
            activeCategory={activeCategory} 
            onSelectCategory={setActiveCategory} 
          />
      )}

      <RankingSelector 
        currentRanking={rankingMethod} 
        onRankingChange={setRankingMethod} 
      />

      {/* Main Focus Area */}
      {sortedTasks.length === 0 ? (
        <div className="text-center py-20 bg-white border-2 border-black border-dashed rounded-lg">
          <h3 className="text-2xl font-bold text-gray-400 mb-2">No tasks found!</h3>
          <p className="text-gray-500 mb-6">You're either extremely productive or procrastinating.</p>
          <Button onClick={() => setIsTaskModalOpen(true)}>Create First Task</Button>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-12">
            {/* Top Task 1 */}
            {topTasks[0] && (
                <div className="relative">
                     <div className="absolute -top-4 -left-4 bg-black text-white px-3 py-1 font-bold text-sm transform -rotate-3 z-10 shadow-[4px_4px_0px_0px_rgba(255,144,232,1)]">
                        FOCUS #1
                     </div>
                     <TaskCard 
                        task={topTasks[0]} 
                        onComplete={handleCompleteTask} 
                        onEdit={handleOpenEdit} 
                        isTopTask={true} 
                     />
                </div>
            )}

            {/* Top Task 2 */}
            {topTasks[1] && (
                <div className="relative">
                     <div className="absolute -top-4 -left-4 bg-black text-white px-3 py-1 font-bold text-sm transform rotate-2 z-10 shadow-[4px_4px_0px_0px_rgba(35,166,213,1)]">
                        FOCUS #2
                     </div>
                     <TaskCard 
                        task={topTasks[1]} 
                        onComplete={handleCompleteTask} 
                        onEdit={handleOpenEdit} 
                        isTopTask={true} 
                     />
                </div>
            )}
        </div>
      )}

      {/* Backup List */}
      {backupTasks.length > 0 && (
        <div className="mt-12">
            <h3 className="text-xl font-bold mb-4 flex items-center gap-2">
                <div className="w-3 h-3 bg-gray-400 rounded-full"></div>
                Up Next ({backupTasks.length})
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 opacity-75">
                {backupTasks.map(task => (
                    <TaskCard 
                        key={task.id} 
                        task={task} 
                        onComplete={handleCompleteTask} 
                        onEdit={handleOpenEdit} 
                        isTopTask={false} 
                    />
                ))}
            </div>
        </div>
      )}

      {/* Modals */}
      <TaskModal 
        isOpen={isTaskModalOpen} 
        onClose={() => { setIsTaskModalOpen(false); setEditingTask(null); }}
        onSave={editingTask ? handleEditTask : handleAddTask}
        initialTask={editingTask}
      />

      <HistoryModal 
        isOpen={isHistoryModalOpen}
        onClose={() => setIsHistoryModalOpen(false)}
        completedTasks={completedTasks}
        onClearHistory={handleClearHistory}
      />
    </div>
  );
}

export enum RankingCriteria {
  PRIORITY = 'PRIORITY',
  BOTHERED = 'BOTHERED',
  DIFFICULTY = 'DIFFICULTY',
  CATEGORY = 'CATEGORY',
}

export interface Task {
  id: string;
  title: string;
  description: string;
  priority: number; // 0-10
  botheredLevel: number; // 0-10
  difficultyLevel: number; // 0-10
  category: string;
  tagColor: string;
  deadline?: string; // ISO string
  createdAt: number;
  completedAt?: number;
}

export interface TagOption {
  color: string;
  label?: string; // Optional label for predefined colors
}

export const DEFAULT_COLORS = [
  '#ff90e8', // Pink
  '#ffc900', // Yellow
  '#23a6d5', // Blue
  '#90e0ef', // Mint
  '#b185db', // Purple
  '#ff6b6b', // Red
  '#feca57', // Orange
  '#48dbfb', // Cyan
  '#ff9ff3', // Rose
  '#54a0ff', // Light Blue
  '#5f27cd', // Dark Purple
  '#1dd1a1', // Green
];

import React from 'react';
import { Task } from '../types';
import { Check, Edit2, Zap, Brain, Calendar, AlertCircle } from 'lucide-react';
import { format } from 'date-fns';

interface TaskCardProps {
  task: Task;
  onComplete: (id: string) => void;
  onEdit: (task: Task) => void;
  isTopTask?: boolean;
}

export const TaskCard: React.FC<TaskCardProps> = ({ task, onComplete, onEdit, isTopTask }) => {
  // Dynamic background based on priority (0-10)
  const getBgColor = () => {
    if (!isTopTask) return 'bg-white';
    if (task.priority >= 8) return 'bg-red-100';
    if (task.priority >= 5) return 'bg-memphis-yellow';
    return 'bg-memphis-mint';
  };

  return (
    <div 
      className={`
        relative border-2 border-black p-5 transition-all
        ${isTopTask ? 'shadow-memphis hover:shadow-memphis-hover transform hover:-translate-y-1' : 'shadow-sm opacity-80 hover:opacity-100'}
        ${getBgColor()}
      `}
    >
      {/* Category Tag Badge */}
      <div 
        className="absolute -top-3 -right-3 px-3 py-1 border-2 border-black text-xs font-bold shadow-[2px_2px_0px_0px_#000]"
        style={{ backgroundColor: task.tagColor }}
      >
        {task.category}
      </div>

      <div className="flex justify-between items-start mb-2 mt-1">
        <h3 className="text-xl font-bold leading-tight w-3/4">{task.title}</h3>
        <button 
          onClick={() => onEdit(task)}
          className="p-1.5 hover:bg-black/10 rounded border border-transparent hover:border-black transition-colors"
          title="Edit Task"
        >
          <Edit2 size={16} />
        </button>
      </div>

      {task.description && (
        <p className="text-sm text-gray-700 mb-4 line-clamp-2">{task.description}</p>
      )}

      {/* Metadata Grid */}
      <div className="grid grid-cols-2 gap-2 text-xs font-medium mb-4">
        <div className="flex items-center gap-1.5" title="Deadline">
           <Calendar size={14} className="text-memphis-purple" />
           {task.deadline ? (
             <span className={new Date(task.deadline) < new Date() ? 'text-red-600 font-bold' : ''}>
               {format(new Date(task.deadline), 'MMM d, h:mm a')}
             </span>
           ) : <span className="text-gray-400">No Deadline</span>}
        </div>

        <div className="flex items-center gap-1.5" title="Difficulty Level">
           <Brain size={14} className="text-memphis-blue" />
           Diff: {task.difficultyLevel}/10
        </div>

        <div className="flex items-center gap-1.5" title="Priority Level">
           <AlertCircle size={14} className={task.priority >= 7 ? 'text-red-500' : 'text-gray-600'} />
           Prio: {task.priority}/10
        </div>

        <div className="flex items-center gap-1.5" title="Bother Level">
           <Zap size={14} className="text-yellow-600" />
           Bother: {task.botheredLevel}/10
        </div>
      </div>

      {/* Complete Action - Only prominent for top tasks */}
      {isTopTask ? (
        <button 
          onClick={() => onComplete(task.id)}
          className="w-full flex items-center justify-center gap-2 bg-black text-white font-bold py-3 hover:bg-gray-800 transition-colors border-2 border-transparent active:border-white"
        >
          <Check size={20} />
          CROSS OUT
        </button>
      ) : (
        <div className="text-center text-xs text-gray-500 italic border-t border-black/10 pt-2">
          Waiting in backup...
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Task, DEFAULT_COLORS } from '../../types';
import { Button } from '../ui/Button';
import { Input } from '../ui/Input';
import { X, AlertCircle, Brain, Zap } from 'lucide-react';

interface TaskModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (task: Omit<Task, 'id' | 'createdAt' | 'completedAt'>) => void;
  initialTask?: Task | null;
}

export const TaskModal: React.FC<TaskModalProps> = ({ isOpen, onClose, onSave, initialTask }) => {
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');

  // Continuous sliders 0-10
  const [priority, setPriority] = useState(5);
  const [botheredLevel, setBotheredLevel] = useState(5);
  const [difficultyLevel, setDifficultyLevel] = useState(5);

  const [category, setCategory] = useState('');
  const [tagColor, setTagColor] = useState(DEFAULT_COLORS[0]);
  const [deadlineDate, setDeadlineDate] = useState('');
  const [deadlineTime, setDeadlineTime] = useState('');

  // Reset or Load initial data
  useEffect(() => {
    if (isOpen) {
      if (initialTask) {
        setTitle(initialTask.title);
        setDescription(initialTask.description || '');
        setPriority(initialTask.priority);
        setBotheredLevel(initialTask.botheredLevel);
        setDifficultyLevel(initialTask.difficultyLevel);
        setCategory(initialTask.category);
        setTagColor(initialTask.tagColor);

        if (initialTask.deadline) {
          const d = new Date(initialTask.deadline);
          // Format for input type="date" and "time"
          setDeadlineDate(d.toISOString().split('T')[0]);
          setDeadlineTime(d.toTimeString().slice(0, 5));
        } else {
            setDeadlineDate('');
            setDeadlineTime('');
        }
      } else {
        // Defaults
        setTitle('');
        setDescription('');
        setPriority(5);
        setBotheredLevel(5);
        setDifficultyLevel(5);
        setCategory('');
        setTagColor(DEFAULT_COLORS[Math.floor(Math.random() * DEFAULT_COLORS.length)]);
        setDeadlineDate('');
        setDeadlineTime('');
      }
    }
  }, [isOpen, initialTask]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!title.trim() || !category.trim()) return;

    let deadlineIso: string | undefined = undefined;
    if (deadlineDate) {
        const time = deadlineTime || '23:59';
        deadlineIso = new Date(`${deadlineDate}T${time}`).toISOString();
    }

    onSave({
      title,
      description,
      priority,
      botheredLevel,
      difficultyLevel,
      category,
      tagColor,
      deadline: deadlineIso,
    });
    onClose();
  };

  if (!isOpen) return null;

  const renderSlider = (
    label: string, 
    value: number, 
    setValue: (val: number) => void, 
    icon: React.ReactNode,
    lowLabel: string,
    highLabel: string,
    colorClass: string
  ) => (
    <div className="bg-gray-50 p-3 border-2 border-black/10 rounded-sm">
      <div className="flex justify-between items-center mb-2">
         <label className="font-bold text-sm flex items-center gap-2">
            {icon} {label}
         </label>
         <span className={`font-black text-lg ${colorClass} bg-white border-2 border-black px-2 py-0.5 min-w-[3rem] text-center`}>
            {value}
         </span>
      </div>
      <div className="flex items-center gap-3">
         <span className="text-xs font-bold text-gray-400 uppercase">{lowLabel}</span>
         <input 
            type="range" 
            min="0" 
            max="10" 
            value={value} 
            onChange={e => setValue(Number(e.target.value))} 
            className="w-full h-3 bg-white rounded-lg appearance-none cursor-pointer border-2 border-black accent-black shadow-[2px_2px_0px_0px_rgba(0,0,0,0.1)]"
         />
         <span className="text-xs font-bold text-gray-400 uppercase">{highLabel}</span>
      </div>
    </div>
  );

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
      <div className="bg-white border-2 border-black shadow-[8px_8px_0px_0px_rgba(255,144,232,1)] w-full max-w-lg max-h-[90vh] overflow-y-auto">
        <div className="p-4 border-b-2 border-black flex justify-between items-center bg-memphis-yellow">
          <h2 className="text-xl font-bold">{initialTask ? 'Edit Task' : 'New Task'}</h2>
          <button onClick={onClose} className="p-1 hover:bg-black/10 rounded"><X size={24} /></button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-5">
          <Input 
            label="What needs to be done?" 
            value={title} 
            onChange={e => setTitle(e.target.value)} 
            placeholder="e.g. Finish the report"
            required
            autoFocus
          />

          <div className="flex flex-col gap-1">
            <label className="font-bold text-sm">Description</label>
            <textarea 
              className="border-2 border-black p-2 shadow-[2px_2px_0px_0px_rgba(0,0,0,1)] focus:outline-none focus:shadow-[4px_4px_0px_0px_rgba(0,0,0,1)] w-full resize-none h-20"
              value={description}
              onChange={e => setDescription(e.target.value)}
              placeholder="Add details..."
            />
          </div>

          <div className="space-y-4">
             {renderSlider('Priority', priority, setPriority, <AlertCircle size={16}/>, 'Low', 'Urgent', 'text-red-500')}
             {renderSlider('Difficulty', difficultyLevel, setDifficultyLevel, <Brain size={16}/>, 'Easy', 'Hard', 'text-memphis-blue')}
             {renderSlider('Bothered Level', botheredLevel, setBotheredLevel, <Zap size={16}/>, 'Chill', 'Annoying', 'text-yellow-600')}
          </div>

          {/* Tag & Color System */}
          <div className="border-2 border-black p-4 bg-gray-50 relative mt-6">
             <label className="absolute -top-3 left-3 bg-gray-50 px-2 font-bold text-sm">Category & Tag</label>
             <div className="flex gap-4 items-end">
                <div className="flex-1">
                    <Input 
                        label="Category Name" 
                        value={category} 
                        onChange={e => setCategory(e.target.value)} 
                        placeholder="e.g. Work, Health"
                        list="existing-categories"
                        required
                    />
                </div>
                <div className="flex flex-col gap-1">
                    <label className="text-xs font-bold">Color</label>
                    <input 
                        type="color" 
                        value={tagColor} 
                        onChange={e => setTagColor(e.target.value)}
                        className="h-[42px] w-[50px] border-2 border-black p-0 cursor-pointer"
                    />
                </div>
             </div>

             {/* Preset Colors */}
             <div className="flex flex-wrap gap-2 mt-3">
                {DEFAULT_COLORS.map(c => (
                    <button
                        key={c}
                        type="button"
                        onClick={() => setTagColor(c)}
                        className={`w-6 h-6 rounded-full border border-black ${tagColor === c ? 'ring-2 ring-offset-1 ring-black scale-110' : ''}`}
                        style={{ backgroundColor: c }}
                    />
                ))}
             </div>
          </div>

          {/* Deadline System */}
          <div className="grid grid-cols-2 gap-4">
             <Input 
                type="date" 
                label="Deadline Date" 
                value={deadlineDate}
                onChange={e => setDeadlineDate(e.target.value)}
             />
             <Input 
                type="time" 
                label="Time" 
                value={deadlineTime}
                onChange={e => setDeadlineTime(e.target.value)}
                disabled={!deadlineDate}
             />
          </div>

          <div className="pt-4 flex justify-end gap-3">
             <Button type="button" variant="secondary" onClick={onClose}>Cancel</Button>
             <Button type="submit" variant="primary">
                 {initialTask ? 'Update Task' : 'Add Task'}
             </Button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { Task, RankingCriteria } from './types';
import { Button } from './components/ui/Button';
import { CategoryFilter } from './components/CategoryFilter';
import { RankingSelector } from './components/RankingSelector';
import { TaskCard } from './components/TaskCard';
import { TaskModal } from './components/modals/TaskModal';
import { HistoryModal } from './components/modals/HistoryModal';
import { Plus, History } from 'lucide-react';

export default function App() {
  // State
  const [tasks, setTasks] = useState<Task[]>([]);
  const [completedTasks, setCompletedTasks] = useState<Task[]>([]);
  const [rankingMethod, setRankingMethod] = useState<RankingCriteria>(RankingCriteria.PRIORITY);
  const [activeCategory, setActiveCategory] = useState<string>('All');

  // Modal States
  const [isTaskModalOpen, setIsTaskModalOpen] = useState(false);
  const [editingTask, setEditingTask] = useState<Task | null>(null);
  const [isHistoryModalOpen, setIsHistoryModalOpen] = useState(false);

  // Persistence on Mount with Migration
  useEffect(() => {
    const storedTasks = localStorage.getItem('memphis-tasks');
    const storedCompleted = localStorage.getItem('memphis-completed');
    const storedRanking = localStorage.getItem('memphis-ranking');

    // Migration helper for old data format
    const migrateTask = (t: any): Task => {
      let priority = typeof t.priority === 'number' ? t.priority : 5;
      if (typeof t.priority === 'string') {
         if (t.priority === 'High') priority = 9;
         else if (t.priority === 'Medium') priority = 5;
         else priority = 2;
      }

      let difficultyLevel = typeof t.difficultyLevel === 'number' ? t.difficultyLevel : 5;
      if (t.difficultyMinutes !== undefined) {
         // Map old minutes to rough 1-10 scale
         difficultyLevel = Math.min(10, Math.ceil((t.difficultyMinutes / 60) * 5));
      }

      return {
        ...t,
        priority,
        difficultyLevel,
        // Ensure defaults for new fields if completely missing
        botheredLevel: t.botheredLevel ?? 5,
      };
    };

    if (storedTasks) {
       const parsed = JSON.parse(storedTasks);
       setTasks(parsed.map(migrateTask));
    }
    if (storedCompleted) {
       const parsed = JSON.parse(storedCompleted);
       setCompletedTasks(parsed.map(migrateTask));
    }
    if (storedRanking) setRankingMethod(storedRanking as RankingCriteria);
  }, []);

  // Persistence on Update
  useEffect(() => {
    localStorage.setItem('memphis-tasks', JSON.stringify(tasks));
  }, [tasks]);

  useEffect(() => {
    localStorage.setItem('memphis-completed', JSON.stringify(completedTasks));
  }, [completedTasks]);

  useEffect(() => {
    localStorage.setItem('memphis-ranking', rankingMethod);
  }, [rankingMethod]);

  // Derived Data
  const categories = useMemo(() => {
    const uniqueCats = new Set(tasks.map(t => t.category).filter(Boolean));
    return Array.from(uniqueCats).sort();
  }, [tasks]);

  const sortedTasks = useMemo(() => {
    let filtered = activeCategory === 'All' 
      ? tasks 
      : tasks.filter(t => t.category === activeCategory);

    return [...filtered].sort((a, b) => {
      switch (rankingMethod) {
        case RankingCriteria.PRIORITY:
          // High Priority Value (e.g. 10) first
          if (b.priority !== a.priority) {
            return b.priority - a.priority;
          }
          return b.createdAt - a.createdAt; 

        case RankingCriteria.BOTHERED:
          // Higher bothered level comes first
          if (b.botheredLevel !== a.botheredLevel) {
            return b.botheredLevel - a.botheredLevel;
          }
          return b.priority - a.priority;

        case RankingCriteria.DIFFICULTY:
          // Hardest first (Higher difficulty level)
          if (b.difficultyLevel !== a.difficultyLevel) {
            return b.difficultyLevel - a.difficultyLevel;
          }
          return b.priority - a.priority;

        case RankingCriteria.CATEGORY:
            // Sort by Category Name AZ, then Priority
            const catCompare = a.category.localeCompare(b.category);
            if (catCompare !== 0) return catCompare;
            return b.priority - a.priority;

        default:
          return b.createdAt - a.createdAt;
      }
    });
  }, [tasks, activeCategory, rankingMethod]);

  // Top 2 tasks to focus on
  const topTasks = sortedTasks.slice(0, 2);
  const backupTasks = sortedTasks.slice(2);

  // Handlers
  const handleAddTask = (taskData: Omit<Task, 'id' | 'createdAt' | 'completedAt'>) => {
    const newTask: Task = {
      ...taskData,
      id: uuidv4(),
      createdAt: Date.now(),
    };
    setTasks(prev => [...prev, newTask]);

    if (activeCategory !== 'All' && taskData.category !== activeCategory) {
        setActiveCategory('All');
    }
  };

  const handleEditTask = (taskData: Omit<Task, 'id' | 'createdAt' | 'completedAt'>) => {
    if (!editingTask) return;

    setTasks(prev => prev.map(t => 
        t.id === editingTask.id 
            ? { ...t, ...taskData } 
            : t
    ));
    setEditingTask(null);
  };

  const handleCompleteTask = (id: string) => {
    const taskToComplete = tasks.find(t => t.id === id);
    if (taskToComplete) {
      const completed: Task = { ...taskToComplete, completedAt: Date.now() };
      setCompletedTasks(prev => [...prev, completed]);
      setTasks(prev => prev.filter(t => t.id !== id));
    }
  };

  const handleOpenEdit = (task: Task) => {
    setEditingTask(task);
    setIsTaskModalOpen(true);
  };

  const handleClearHistory = () => {
      if(window.confirm("Are you sure you want to clear all history?")) {
          setCompletedTasks([]);
      }
  };

  return (
    <div className="min-h-screen pb-20 px-4 md:px-8 max-w-5xl mx-auto pt-8">

      {/* Header */}
      <header className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
        <div>
           <h1 className="text-4xl md:text-5xl font-black text-black tracking-tight mb-2 relative inline-block">
             FOCUS TASKS
             <div className="absolute -bottom-2 left-0 w-full h-3 bg-memphis-yellow -z-10 opacity-70 transform -rotate-1"></div>
           </h1>
           <p className="text-gray-600 font-medium">Get it done. Two at a time.</p>
        </div>

        <div className="flex gap-3">
            <Button onClick={() => setIsHistoryModalOpen(true)} variant="secondary" className="flex items-center gap-2">
                <History size={18} /> History ({completedTasks.length})
            </Button>
            <Button onClick={() => { setEditingTask(null); setIsTaskModalOpen(true); }} className="flex items-center gap-2">
                <Plus size={20} strokeWidth={3} /> Add Task
            </Button>
        </div>
