import React, { useState, useEffect, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { Task, RankingCriteria } from './types';
import { Button } from './components/ui/Button';
import { CategoryFilter } from './components/CategoryFilter';
import { RankingSelector } from './components/RankingSelector';
import { TaskCard } from './components/TaskCard';
import { TaskModal } from './components/modals/TaskModal';
import { HistoryModal } from './components/modals/HistoryModal';
import { Plus, History, Sun, Moon } from 'lucide-react';

// Migration helper
const migrateTask = (t: any): Task => {
  let priority = typeof t.priority === 'number' ? t.priority : 5;
  if (typeof t.priority === 'string') {
     if (t.priority === 'High') priority = 9;
     else if (t.priority === 'Medium') priority = 5;
     else priority = 2;
  }

  let difficultyLevel = typeof t.difficultyLevel === 'number' ? t.difficultyLevel : 5;
  if (t.difficultyMinutes !== undefined) {
     difficultyLevel = Math.min(10, Math.ceil((t.difficultyMinutes / 60) * 5));
  }

  return {
    ...t,
    priority,
    difficultyLevel,
    botheredLevel: t.botheredLevel ?? 5,
  };
};

export default function App() {
  // Theme State
  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    try {
      if (typeof window !== 'undefined') {
        const stored = localStorage.getItem('memphis-theme');
        if (stored === 'dark' || stored === 'light') return stored;
        return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
      }
    } catch (e) {}
    return 'light';
  });

  // Data States
  const [tasks, setTasks] = useState<Task[]>(() => {
    try {
      const stored = localStorage.getItem('memphis-tasks');
      if (stored) return JSON.parse(stored).map(migrateTask);
    } catch (e) {}
    return [];
  });

  const [completedTasks, setCompletedTasks] = useState<Task[]>(() => {
    try {
      const stored = localStorage.getItem('memphis-completed');
      if (stored) return JSON.parse(stored).map(migrateTask);
    } catch (e) {}
    return [];
  });

  const [rankingMethod, setRankingMethod] = useState<RankingCriteria>(() => {
    try {
      const stored = localStorage.getItem('memphis-ranking');
      if (stored) return stored as RankingCriteria;
    } catch (e) {}
    return RankingCriteria.PRIORITY;
  });

  const [activeCategory, setActiveCategory] = useState<string>('All');

  // Last Used Category State for UX convenience
  const [lastUsedCategory, setLastUsedCategory] = useState<string>(() => {
    try {
      return localStorage.getItem('memphis-last-category') || '';
    } catch { return ''; }
  });

  // Modal States
  const [isTaskModalOpen, setIsTaskModalOpen] = useState(false);
  const [editingTask, setEditingTask] = useState<Task | null>(null);
  const [isHistoryModalOpen, setIsHistoryModalOpen] = useState(false);

  // Apply Theme Effect
  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
    localStorage.setItem('memphis-theme', theme);
  }, [theme]);

  // Persistence Effects
  useEffect(() => {
    localStorage.setItem('memphis-tasks', JSON.stringify(tasks));
  }, [tasks]);

  useEffect(() => {
    localStorage.setItem('memphis-completed', JSON.stringify(completedTasks));
  }, [completedTasks]);

  useEffect(() => {
    localStorage.setItem('memphis-ranking', rankingMethod);
  }, [rankingMethod]);

  const toggleTheme = () => {
    setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  // Derived Data
  const categories = useMemo(() => {
    const uniqueCats = new Set(tasks.map(t => t.category).filter(Boolean));
    return Array.from(uniqueCats).sort();
  }, [tasks]);

  // Map categories to their last used colors for smart suggestion
  const categoryColors = useMemo(() => {
    const map: Record<string, string> = {};
    // Iterate through all tasks to build the map
    tasks.forEach(t => {
      if (t.category) map[t.category] = t.tagColor || '#ff90e8';
    });
    return map;
  }, [tasks]);

  const sortedTasks = useMemo(() => {
    let filtered = activeCategory === 'All' 
      ? tasks 
      : tasks.filter(t => t.category === activeCategory);

    return [...filtered].sort((a, b) => {
      switch (rankingMethod) {
        case RankingCriteria.PRIORITY:
          if (b.priority !== a.priority) return b.priority - a.priority;
          return b.createdAt - a.createdAt; 
        case RankingCriteria.BOTHERED:
          if (b.botheredLevel !== a.botheredLevel) return b.botheredLevel - a.botheredLevel;
          return b.priority - a.priority;
        case RankingCriteria.DIFFICULTY:
          if (b.difficultyLevel !== a.difficultyLevel) return b.difficultyLevel - a.difficultyLevel;
          return b.priority - a.priority;
        case RankingCriteria.CATEGORY:
            const catCompare = a.category.localeCompare(b.category);
            if (catCompare !== 0) return catCompare;
            return b.priority - a.priority;
        default:
          return b.createdAt - a.createdAt;
      }
    });
  }, [tasks, activeCategory, rankingMethod]);

  const topTasks = sortedTasks.slice(0, 2);
  const backupTasks = sortedTasks.slice(2);

  // Handlers
  const handleAddTask = (taskData: Omit<Task, 'id' | 'createdAt' | 'completedAt'>) => {
    const newTask: Task = { ...taskData, id: uuidv4(), createdAt: Date.now() };
    setTasks(prev => [...prev, newTask]);

    // Update last used category persistence
    setLastUsedCategory(taskData.category);
    localStorage.setItem('memphis-last-category', taskData.category);

    if (activeCategory !== 'All' && taskData.category !== activeCategory) setActiveCategory('All');
  };

  const handleEditTask = (taskData: Omit<Task, 'id' | 'createdAt' | 'completedAt'>) => {
    if (!editingTask) return;
    setTasks(prev => prev.map(t => t.id === editingTask.id ? { ...t, ...taskData } : t));

    // Also update preference on edit
    setLastUsedCategory(taskData.category);
    localStorage.setItem('memphis-last-category', taskData.category);

    setEditingTask(null);
  };

  const handleCompleteTask = (id: string) => {
    const taskToComplete = tasks.find(t => t.id === id);
    if (taskToComplete) {
      const completed: Task = { ...taskToComplete, completedAt: Date.now() };
      setCompletedTasks(prev => [...prev, completed]);
      setTasks(prev => prev.filter(t => t.id !== id));
    }
  };

  const handleRestoreTask = (id: string) => {
    const taskToRestore = completedTasks.find(t => t.id === id);
    if (taskToRestore) {
        setCompletedTasks(prev => prev.filter(t => t.id !== id));
        const restoredTask = { ...taskToRestore };
        delete restoredTask.completedAt;
        setTasks(prev => [...prev, restoredTask]);
    }
  };

  const handleDeleteTask = (id: string) => {
    const taskToDelete = tasks.find(t => t.id === id);
    if (taskToDelete) {
        setTasks(prev => prev.filter(t => t.id !== id));
        if (editingTask && editingTask.id === id) {
            setIsTaskModalOpen(false);
            setEditingTask(null);
        }
    }
  };

  const handleOpenEdit = (task: Task) => {
    setEditingTask(task);
    setIsTaskModalOpen(true);
  };

  const handleClearHistory = () => {
      setCompletedTasks([]);
  };

  return (
    <div className={`min-h-screen transition-colors duration-300 ${theme === 'dark' ? 'bg-memphis-dark' : 'bg-memphis-light'}`}>
      <div className="pb-20 px-4 md:px-8 max-w-5xl mx-auto pt-8">

        {/* Header */}
        <header className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
          <div>
            <h1 className="text-4xl md:text-5xl font-black text-black dark:text-white tracking-tight mb-2 relative inline-block transition-colors">
              FocusTwo
              <div className="absolute -bottom-2 left-0 w-full h-3 bg-memphis-yellow -z-10 opacity-70 transform -rotate-1"></div>
            </h1>
            <p className="text-gray-600 dark:text-gray-400 font-medium transition-colors">Get it done. Two at a time.</p>
          </div>

          <div className="flex flex-wrap items-center justify-center gap-3">
              <Button 
                onClick={toggleTheme} 
                variant="secondary" 
                className="flex items-center gap-2"
                title={theme === 'light' ? 'Switch to Night Mode' : 'Switch to Day Mode'}
              >
                  {theme === 'light' ? <Moon size={18} /> : <Sun size={18} />}
              </Button>
              <Button onClick={() => setIsHistoryModalOpen(true)} variant="secondary" className="flex items-center gap-2">
                  <History size={18} /> History ({completedTasks.length})
              </Button>
              <Button onClick={() => { setEditingTask(null); setIsTaskModalOpen(true); }} className="flex items-center gap-2">
                  <Plus size={20} strokeWidth={3} /> Add Task
              </Button>
          </div>
        </header>

        {/* Controls */}
        {categories.length > 0 && (
            <CategoryFilter 
              categories={categories} 
              activeCategory={activeCategory} 
              onSelectCategory={setActiveCategory} 
            />
        )}

        <RankingSelector 
          currentRanking={rankingMethod} 
          onRankingChange={setRankingMethod} 
        />

        {/* Main Focus Area */}
        {sortedTasks.length === 0 ? (
          <div className="text-center py-20 bg-white dark:bg-memphis-dark-surface border-2 border-black dark:border-white border-dashed rounded-lg transition-colors">
            <h3 className="text-2xl font-bold text-gray-400 dark:text-gray-500 mb-2">No tasks found!</h3>
            <p className="text-gray-500 dark:text-gray-400 mb-6">You're either extremely productive or procrastinating.</p>
            <Button onClick={() => setIsTaskModalOpen(true)}>Create First Task</Button>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-12">
              {/* Top Task 1 */}
              {topTasks[0] && (
                  <div className="relative">
                      <div className="absolute -top-4 -left-4 bg-black dark:bg-white text-white dark:text-black px-3 py-1 font-bold text-sm transform -rotate-3 z-10 shadow-[4px_4px_0px_0px_var(--memphis-shadow)] transition-colors">
                          FOCUS #1
                      </div>
                      <TaskCard 
                          task={topTasks[0]} 
                          onComplete={handleCompleteTask} 
                          onEdit={handleOpenEdit} 
                          onDelete={handleDeleteTask}
                          isTopTask={true} 
                      />
                  </div>
              )}

              {/* Top Task 2 */}
              {topTasks[1] && (
                  <div className="relative">
                      <div className="absolute -top-4 -left-4 bg-black dark:bg-white text-white dark:text-black px-3 py-1 font-bold text-sm transform rotate-2 z-10 shadow-[4px_4px_0px_0px_var(--memphis-shadow)] transition-colors">
                          FOCUS #2
                      </div>
                      <TaskCard 
                          task={topTasks[1]} 
                          onComplete={handleCompleteTask} 
                          onEdit={handleOpenEdit} 
                          onDelete={handleDeleteTask}
                          isTopTask={true} 
                      />
                  </div>
              )}
          </div>
        )}

        {/* Backup List */}
        {backupTasks.length > 0 && (
          <div className="mt-12">
              <h3 className="text-xl font-bold mb-4 flex items-center gap-2 text-black dark:text-white transition-colors">
                  <div className="w-3 h-3 bg-gray-400 rounded-full"></div>
                  Up Next ({backupTasks.length})
              </h3>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 opacity-75">
                  {backupTasks.map(task => (
                      <TaskCard 
                          key={task.id} 
                          task={task} 
                          onComplete={handleCompleteTask} 
                          onEdit={handleOpenEdit} 
                          onDelete={handleDeleteTask}
                          isTopTask={false} 
                      />
                  ))}
              </div>
          </div>
        )}

        {/* Modals */}
        <TaskModal 
          isOpen={isTaskModalOpen} 
          onClose={() => { setIsTaskModalOpen(false); setEditingTask(null); }}
          onSave={editingTask ? handleEditTask : handleAddTask}
          onDelete={handleDeleteTask}
          initialTask={editingTask}
          existingCategories={categories}
          categoryColors={categoryColors}
          defaultCategory={lastUsedCategory}
        />

        <HistoryModal 
          isOpen={isHistoryModalOpen}
          onClose={() => setIsHistoryModalOpen(false)}
          completedTasks={completedTasks}
          onClearHistory={handleClearHistory}
          onRestore={handleRestoreTask}
        />
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { Task, DEFAULT_COLORS } from '../../types';
import { Button } from '../ui/Button';
import { Input } from '../ui/Input';
import { X, AlertCircle, Brain, Zap, Trash2, Tag } from 'lucide-react';

interface TaskModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (task: Omit<Task, 'id' | 'createdAt' | 'completedAt'>) => void;
  onDelete?: (id: string) => void;
  initialTask?: Task | null;
  existingCategories?: string[];
  categoryColors?: Record<string, string>;
  defaultCategory?: string;
}

export const TaskModal: React.FC<TaskModalProps> = ({ 
  isOpen, 
  onClose, 
  onSave, 
  onDelete, 
  initialTask,
  existingCategories = [],
  categoryColors = {},
  defaultCategory = ''
}) => {
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');

  // Continuous sliders 0-10
  const [priority, setPriority] = useState(5);
  const [botheredLevel, setBotheredLevel] = useState(5);
  const [difficultyLevel, setDifficultyLevel] = useState(5);

  const [category, setCategory] = useState('');
  const [tagColor, setTagColor] = useState(DEFAULT_COLORS[0]);
  const [deadlineDate, setDeadlineDate] = useState('');
  const [deadlineTime, setDeadlineTime] = useState('');

  // Reset or Load initial data
  useEffect(() => {
    if (isOpen) {
      if (initialTask) {
        setTitle(initialTask.title);
        setDescription(initialTask.description || '');
        setPriority(initialTask.priority);
        setBotheredLevel(initialTask.botheredLevel);
        setDifficultyLevel(initialTask.difficultyLevel);
        setCategory(initialTask.category);
        setTagColor(initialTask.tagColor);

        if (initialTask.deadline) {
          const d = new Date(initialTask.deadline);
          // Format for input type="date" and "time"
          setDeadlineDate(d.toISOString().split('T')[0]);
          setDeadlineTime(d.toTimeString().slice(0, 5));
        } else {
            setDeadlineDate('');
            setDeadlineTime('');
        }
      } else {
        // Defaults for new task
        setTitle('');
        setDescription('');
        setPriority(5);
        setBotheredLevel(5);
        setDifficultyLevel(5);

        // Auto-fill category from memory
        const startCategory = defaultCategory;
        setCategory(startCategory);

        // Auto-fill color if category exists
        if (startCategory && categoryColors[startCategory]) {
            setTagColor(categoryColors[startCategory]);
        } else {
            setTagColor(DEFAULT_COLORS[Math.floor(Math.random() * DEFAULT_COLORS.length)]);
        }

        setDeadlineDate('');
        setDeadlineTime('');
      }
    }
  }, [isOpen, initialTask, defaultCategory, categoryColors]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!title.trim() || !category.trim()) return;

    let deadlineIso: string | undefined = undefined;
    if (deadlineDate) {
        const time = deadlineTime || '23:59';
        deadlineIso = new Date(`${deadlineDate}T${time}`).toISOString();
    }

    onSave({
      title,
      description,
      priority,
      botheredLevel,
      difficultyLevel,
      category,
      tagColor,
      deadline: deadlineIso,
    });
    onClose();
  };

  const handleDelete = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (initialTask && onDelete) {
        onDelete(initialTask.id);
    }
  };

  const handleCategorySelect = (cat: string) => {
      setCategory(cat);
      if (categoryColors[cat]) {
          setTagColor(categoryColors[cat]);
      }
  };

  if (!isOpen) return null;

  const renderSlider = (
    label: string, 
    value: number, 
    setValue: (val: number) => void, 
    icon: React.ReactNode,
    lowLabel: string,
    highLabel: string,
    colorClass: string
  ) => (
    <div className="bg-gray-50 dark:bg-white/5 p-3 border-2 border-black/10 dark:border-white/20 rounded-sm">
      <div className="flex justify-between items-center mb-2">
         <label className="font-bold text-sm flex items-center gap-2 dark:text-white">
            {icon} {label}
         </label>
         <span className={`font-black text-lg ${colorClass} bg-white dark:bg-black border-2 border-black dark:border-white px-2 py-0.5 min-w-[3rem] text-center`}>
            {value}
         </span>
      </div>
      <div className="flex items-center gap-3">
         <span className="text-xs font-bold text-gray-400 uppercase">{lowLabel}</span>
         <input 
            type="range" 
            min="0" 
            max="10" 
            value={value} 
            onChange={e => setValue(Number(e.target.value))} 
            className="w-full h-3 bg-white rounded-lg appearance-none cursor-pointer border-2 border-black accent-black dark:accent-white shadow-[2px_2px_0px_0px_rgba(0,0,0,0.1)]"
         />
         <span className="text-xs font-bold text-gray-400 uppercase">{highLabel}</span>
      </div>
    </div>
  );

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
      <div className="bg-white dark:bg-memphis-dark-surface border-2 border-black dark:border-white shadow-[8px_8px_0px_0px_rgba(255,144,232,1)] dark:shadow-[8px_8px_0px_0px_var(--memphis-shadow)] w-full max-w-lg max-h-[90vh] overflow-y-auto transition-colors">
        <div className="p-4 border-b-2 border-black dark:border-white flex justify-between items-center bg-memphis-yellow dark:bg-yellow-600">
          <h2 className="text-xl font-bold text-black dark:text-white">{initialTask ? 'Edit Task' : 'New Task'}</h2>
          <button onClick={onClose} className="p-1 hover:bg-black/10 rounded dark:text-white dark:hover:bg-white/20"><X size={24} /></button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-5">
          <Input 
            label="What needs to be done?" 
            value={title} 
            onChange={e => setTitle(e.target.value)} 
            placeholder="e.g. Finish the report"
            required
            autoFocus
          />

          <div className="flex flex-col gap-1">
            <label className="font-bold text-sm dark:text-white">Description</label>
            <textarea 
              className="border-2 border-black dark:border-white p-2 shadow-[2px_2px_0px_0px_rgba(0,0,0,1)] dark:shadow-[2px_2px_0px_0px_var(--memphis-shadow)] focus:outline-none focus:shadow-[4px_4px_0px_0px_rgba(0,0,0,1)] dark:focus:shadow-[4px_4px_0px_0px_var(--memphis-shadow)] w-full resize-none h-20 bg-white dark:bg-memphis-dark-surface dark:text-white"
              value={description}
              onChange={e => setDescription(e.target.value)}
              placeholder="Add details..."
            />
          </div>

          <div className="space-y-4">
             {renderSlider('Priority', priority, setPriority, <AlertCircle size={16}/>, 'Low', 'Urgent', 'text-red-500')}
             {renderSlider('Difficulty', difficultyLevel, setDifficultyLevel, <Brain size={16}/>, 'Easy', 'Hard', 'text-memphis-blue')}
             {renderSlider('Bothered Level', botheredLevel, setBotheredLevel, <Zap size={16}/>, 'Chill', 'Annoying', 'text-yellow-600')}
          </div>

          {/* Tag & Color System */}
          <div className="border-2 border-black dark:border-white p-4 bg-gray-50 dark:bg-white/5 relative mt-6">
             <label className="absolute -top-3 left-3 bg-gray-50 dark:bg-memphis-dark-surface dark:text-white border dark:border-white px-2 font-bold text-sm">Category & Tag</label>
             <div className="flex gap-4 items-end">
                <div className="flex-1">
                    <Input 
                        label="Category Name" 
                        value={category} 
                        onChange={e => setCategory(e.target.value)} 
                        placeholder="e.g. Work, Health"
                        list="existing-categories"
                        required
                    />
                    <datalist id="existing-categories">
                        {existingCategories.map(cat => <option key={cat} value={cat} />)}
                    </datalist>

                    {/* Quick Select Chips */}
                    {existingCategories.length > 0 && (
                        <div className="flex flex-wrap gap-2 mt-2">
                            {existingCategories.slice(0, 6).map(cat => (
                                <button
                                    key={cat}
                                    type="button"
                                    onClick={() => handleCategorySelect(cat)}
                                    className="text-xs font-bold px-2 py-1 rounded-sm border border-black dark:border-white hover:opacity-80 transition-transform active:scale-95 text-black shadow-[1px_1px_0px_0px_rgba(0,0,0,0.5)]"
                                    style={{ backgroundColor: categoryColors[cat] || '#fff' }}
                                    title="Quick select category"
                                >
                                    {cat}
                                </button>
                            ))}
                        </div>
                    )}
                </div>
                <div className="flex flex-col gap-1">
                    <label className="text-xs font-bold dark:text-white">Color</label>
                    <input 
                        type="color" 
                        value={tagColor} 
                        onChange={e => setTagColor(e.target.value)}
                        className="h-[42px] w-[50px] border-2 border-black dark:border-white p-0 cursor-pointer"
                    />
                </div>
             </div>

             {/* Preset Colors */}
             <div className="flex flex-wrap gap-2 mt-3">
                {DEFAULT_COLORS.map(c => (
                    <button
                        key={c}
                        type="button"
                        onClick={() => setTagColor(c)}
                        className={`w-6 h-6 rounded-full border border-black dark:border-white ${tagColor === c ? 'ring-2 ring-offset-1 ring-black dark:ring-white scale-110' : ''}`}
                        style={{ backgroundColor: c }}
                    />
                ))}
             </div>
          </div>

          {/* Deadline System */}
          <div className="grid grid-cols-2 gap-4">
             <Input 
                type="date" 
                label="Deadline Date" 
                value={deadlineDate}
                onChange={e => setDeadlineDate(e.target.value)}
             />
             <Input 
                type="time" 
                label="Time" 
                value={deadlineTime}
                onChange={e => setDeadlineTime(e.target.value)}
                disabled={!deadlineDate}
             />
          </div>

          <div className="pt-4 flex justify-between gap-3 items-center">
             {initialTask ? (
                 <Button type="button" variant="danger" onClick={handleDelete} className="flex items-center gap-2">
                    <Trash2 size={16} /> Delete
                 </Button>
             ) : (
                 <div></div> 
             )}

             <div className="flex gap-3">
                 <Button type="button" variant="secondary" onClick={onClose}>Cancel</Button>
                 <Button type="submit" variant="primary">
                     {initialTask ? 'Update Task' : 'Add Task'}
                 </Button>
             </div>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Task } from '../types';
import { Check, Edit2, Zap, Brain, Calendar, AlertCircle, Trash2, ChevronDown, ChevronUp } from 'lucide-react';
import { format } from 'date-fns';

interface TaskCardProps {
  task: Task;
  onComplete: (id: string) => void;
  onEdit: (task: Task) => void;
  onDelete: (id: string) => void;
  isTopTask?: boolean;
}

export const TaskCard: React.FC<TaskCardProps> = ({ task, onComplete, onEdit, onDelete, isTopTask }) => {
  const [isExpanded, setIsExpanded] = useState(false);

  // Dynamic background based on priority (0-10)
  const getBgColor = () => {
    if (!isTopTask) return 'bg-white dark:bg-memphis-dark-surface'; // Backup tasks need dark bg in dark mode
    if (task.priority >= 8) return 'bg-red-100 dark:bg-red-900/40';
    if (task.priority >= 5) return 'bg-memphis-yellow dark:bg-yellow-600/80';
    return 'bg-memphis-mint dark:bg-cyan-900/60';
  };

  // Text color logic
  const getTextColor = () => {
      return 'text-black dark:text-white';
  };

  return (
    <div 
      className={`
        relative border-2 border-black dark:border-white transition-all duration-300 group
        ${isTopTask ? 'shadow-memphis hover:shadow-memphis-hover' : 'shadow-sm dark:shadow-none opacity-80 hover:opacity-100'}
        ${getBgColor()}
        ${getTextColor()}
        ${isExpanded ? 'p-5' : 'p-3'}
      `}
    >
      {/* Category Tag Badge */}
      <div 
        className={`absolute -top-3 -right-3 px-3 py-1 border-2 border-black dark:border-white text-black dark:text-white text-xs font-bold shadow-[2px_2px_0px_0px_#000] dark:shadow-[2px_2px_0px_0px_var(--memphis-shadow)] z-20 pointer-events-none transition-transform origin-bottom-left ${isExpanded ? 'scale-100' : 'scale-90'}`}
        style={{ backgroundColor: task.tagColor }}
      >
        {task.category}
      </div>

      {/* Header Row: Always Visible */}
      <div className="flex justify-between items-center gap-2 relative z-30">

        {/* Title (Clickable to Toggle) */}
        <h3 
            className={`font-bold leading-tight flex-1 pr-2 break-words cursor-pointer select-none transition-all ${isExpanded ? 'text-xl' : 'text-lg line-clamp-1'}`}
            onClick={() => setIsExpanded(!isExpanded)}
            title="Click to expand/collapse"
        >
            {task.title}
        </h3>

        {/* Controls */}
        <div className="flex items-center gap-3 shrink-0">
            {/* Tiny Edit/Delete Icons */}
            <div className="flex gap-1 bg-white dark:bg-black border-2 border-black dark:border-white p-0.5 shadow-[2px_2px_0px_0px_rgba(0,0,0,0.1)]">
                <button 
                  onClick={(e) => { e.stopPropagation(); onEdit(task); }}
                  className="p-1 hover:bg-black dark:hover:bg-white text-black dark:text-white dark:hover:text-black hover:text-white transition-colors flex items-center justify-center"
                  title="Edit Task"
                  type="button"
                >
                  <Edit2 size={14} />
                </button>
                <div className="w-[1px] bg-black/10 dark:bg-white/20 mx-0.5"></div>
                <button 
                  onClick={(e) => { e.stopPropagation(); onDelete(task.id); }}
                  className="p-1 hover:bg-red-600 text-red-600 hover:text-white transition-colors flex items-center justify-center"
                  title="Delete Task"
                  type="button"
                >
                  <Trash2 size={14} />
                </button>
            </div>

            {/* Expand/Collapse Arrow Button */}
            <button
                onClick={(e) => { e.stopPropagation(); setIsExpanded(!isExpanded); }}
                className="w-8 h-8 flex items-center justify-center bg-black dark:bg-white text-white dark:text-black border-2 border-transparent hover:scale-110 transition-transform rounded-full shadow-sm"
                title={isExpanded ? "Roll up" : "Expand"}
            >
                {isExpanded ? <ChevronUp size={20} strokeWidth={3} /> : <ChevronDown size={20} strokeWidth={3} />}
            </button>
        </div>
      </div>

      {/* Expanded Content: Hidden by default */}
      {isExpanded && (
        <div className="mt-4 pt-4 border-t-2 border-black/10 dark:border-white/10 animate-in fade-in slide-in-from-top-1 duration-200">
            {task.description && (
                <p className="text-sm text-gray-700 dark:text-gray-300 mb-4 break-words relative z-10">{task.description}</p>
            )}

            {/* Metadata Grid */}
            <div className="grid grid-cols-2 gap-2 text-xs font-medium mb-4 relative z-10 text-gray-800 dark:text-gray-200">
                <div className="flex items-center gap-1.5" title="Deadline">
                <Calendar size={14} className="text-memphis-purple dark:text-purple-300" />
                {task.deadline ? (
                    <span className={new Date(task.deadline) < new Date() ? 'text-red-600 dark:text-red-400 font-bold' : ''}>
                    {format(new Date(task.deadline), 'MMM d, h:mm a')}
                    </span>
                ) : <span className="text-gray-400 dark:text-gray-500">No Deadline</span>}
                </div>

                <div className="flex items-center gap-1.5" title="Difficulty Level">
                <Brain size={14} className="text-memphis-blue dark:text-blue-300" />
                Diff: {task.difficultyLevel}/10
                </div>

                <div className="flex items-center gap-1.5" title="Priority Level">
                <AlertCircle size={14} className={task.priority >= 7 ? 'text-red-500 dark:text-red-400' : 'text-gray-600 dark:text-gray-400'} />
                Prio: {task.priority}/10
                </div>

                <div className="flex items-center gap-1.5" title="Bother Level">
                <Zap size={14} className="text-yellow-600 dark:text-yellow-400" />
                Bother: {task.botheredLevel}/10
                </div>
            </div>

            {/* Complete Action */}
            {isTopTask ? (
                <button 
                onClick={(e) => { e.stopPropagation(); onComplete(task.id); }}
                className="w-full flex items-center justify-center gap-2 bg-black dark:bg-white text-white dark:text-black font-bold py-3 hover:bg-gray-800 dark:hover:bg-gray-200 transition-colors border-2 border-transparent active:border-white dark:active:border-black relative z-20 cursor-pointer shadow-[2px_2px_0px_0px_rgba(0,0,0,0.2)]"
                >
                <Check size={20} />
                CROSS OUT
                </button>
            ) : (
                <div className="text-center text-xs text-gray-500 dark:text-gray-500 italic pt-2 relative z-10">
                Waiting in backup...
                </div>
            )}
        </div>
      )}
    </div>
  );
};

